import httpx, json
qs = {'q': params['q'], 'per_page': int(params.get('per_page') or 10)}
r = httpx.get('https://api.github.com/search/repositories', params=qs,
              headers={'Accept': 'application/vnd.github+json'})
data = r.json()
result = {'ok': r.status_code == 200,
          'total': data.get('total_count', 0),
          'items': [{'name': i['full_name'], 'stars': i['stargazers_count'],
                     'url': i['html_url'], 'description': i.get('description')}
                    for i in data.get('items', [])]}
